mapper.select:
SELECT 账户编号 AS accountId, DATE_FORMAT(交易日期, '%Y-%m-%d') AS transactionDate, SUM(CASE WHEN 交易类型 = 'INCOME' THEN 交易金额 ELSE 0 END) AS dayIncome, SUM(CASE WHEN 交易类型 = 'EXPENDITURE' THEN 交易金额 ELSE 0 END) AS dayExpenditure FROM FUND_TRANSACTION WHERE 账户编号 IN
#{id}
AND DATE_FORMAT(交易日期, '%Y-%m-%d') >= #{startDate} AND DATE_FORMAT(交易日期, '%Y-%m-%d') <= #{endDate} GROUP BY 账户编号, DATE_FORMAT(交易日期, '%Y-%m-%d') ORDER BY transactionDate ASC

SELECT base.accountId AS accountId, base.endBalance AS initialBalance, base.periodStart AS periodStart FROM ( SELECT accounts.accountId AS accountId, CONCAT(period_choice.chosenYear, '-', LPAD(period_choice.chosenMonth, 2, '0'), '-01') AS periodStart, COALESCE(init.initialBalance, 0) + COALESCE(flow.netAmount, 0) AS endBalance FROM ( SELECT 账户编号 AS accountId FROM FUND_ACCOUNT WHERE 账户编号 IN
#{id}
) accounts CROSS JOIN ( SELECT CASE WHEN #{useLatestClosedPeriodFallback} AND latest.latestYear IS NOT NULL AND DATE(CONCAT(req.reqYear, '-', LPAD(req.reqMonth, 2, '0'), '-01')) > DATE(CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01')) THEN latest.latestYear ELSE req.reqYear END AS chosenYear, CASE WHEN #{useLatestClosedPeriodFallback} AND latest.latestMonth IS NOT NULL AND DATE(CONCAT(req.reqYear, '-', LPAD(req.reqMonth, 2, '0'), '-01')) > DATE(CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01')) THEN latest.latestMonth ELSE req.reqMonth END AS chosenMonth, CASE WHEN #{useLatestClosedPeriodFallback} AND latest.latestYear IS NOT NULL AND DATE(CONCAT(req.reqYear, '-', LPAD(req.reqMonth, 2, '0'), '-01')) > DATE(CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01')) THEN LAST_DAY(CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01')) ELSE #{endDate} END AS flowEndDate FROM ( SELECT YEAR(STR_TO_DATE(#{endDate}, '%Y-%m-%d')) AS reqYear, MONTH(STR_TO_DATE(#{endDate}, '%Y-%m-%d')) AS reqMonth ) req LEFT JOIN ( SELECT p2.年份 AS latestYear, p2.月份 AS latestMonth FROM FUND_PERIOD p2 WHERE p2.是否已结账 = 1 AND DATE(CONCAT(p2.年份, '-', LPAD(p2.月份, 2, '0'), '-01')) <= STR_TO_DATE(#{endDate}, '%Y-%m-%d') ORDER BY p2.年份 DESC, p2.月份 DESC LIMIT 1 ) latest ON 1 = 1 ) period_choice LEFT JOIN ( SELECT b.账户编号 AS accountId, b.期初余额 AS initialBalance, p.年份 AS periodYear, p.月份 AS periodMonth FROM FUND_ACCOUNT_INITIAL_BALANCE b INNER JOIN FUND_PERIOD p ON p.账期编号 = b.账期编号 WHERE b.账户编号 IN
#{id}
) init ON init.accountId = accounts.accountId AND init.periodYear = period_choice.chosenYear AND init.periodMonth = period_choice.chosenMonth LEFT JOIN ( SELECT ft.账户编号 AS accountId, SUM(CASE WHEN ft.交易类型 = 'INCOME' THEN ft.交易金额 ELSE -ft.交易金额 END) AS netAmount FROM FUND_TRANSACTION ft CROSS JOIN ( SELECT CASE WHEN #{useLatestClosedPeriodFallback} AND latest.latestYear IS NOT NULL AND DATE(CONCAT(req.reqYear, '-', LPAD(req.reqMonth, 2, '0'), '-01')) > DATE(CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01')) THEN CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01') ELSE CONCAT(req.reqYear, '-', LPAD(req.reqMonth, 2, '0'), '-01') END AS flowStartDate, CASE WHEN #{useLatestClosedPeriodFallback} AND latest.latestYear IS NOT NULL AND DATE(CONCAT(req.reqYear, '-', LPAD(req.reqMonth, 2, '0'), '-01')) > DATE(CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01')) THEN LAST_DAY(CONCAT(latest.latestYear, '-', LPAD(latest.latestMonth, 2, '0'), '-01')) ELSE #{endDate} END AS flowEndDate FROM ( SELECT YEAR(STR_TO_DATE(#{endDate}, '%Y-%m-%d')) AS reqYear, MONTH(STR_TO_DATE(#{endDate}, '%Y-%m-%d')) AS reqMonth ) req LEFT JOIN ( SELECT p2.年份 AS latestYear, p2.月份 AS latestMonth FROM FUND_PERIOD p2 WHERE p2.是否已结账 = 1 AND DATE(CONCAT(p2.年份, '-', LPAD(p2.月份, 2, '0'), '-01')) <= STR_TO_DATE(#{endDate}, '%Y-%m-%d') ORDER BY p2.年份 DESC, p2.月份 DESC LIMIT 1 ) latest ON 1 = 1 ) flow_range WHERE ft.账户编号 IN
#{id}
AND DATE_FORMAT(ft.交易日期, '%Y-%m-%d') >= flow_range.flowStartDate AND DATE_FORMAT(ft.交易日期, '%Y-%m-%d') <= flow_range.flowEndDate GROUP BY ft.账户编号 ) flow ON flow.accountId = accounts.accountId ) base ORDER BY base.accountId ASC

SELECT b.账户编号 AS accountId, b.期初余额 AS initialBalance, latest.年份 AS year, latest.lastClosedMonth AS closedMonth FROM FUND_ACCOUNT_INITIAL_BALANCE b INNER JOIN FUND_PERIOD p ON p.账期编号 = b.账期编号 INNER JOIN ( SELECT 年份, MAX(月份) AS lastClosedMonth, CASE WHEN MAX(月份) = 12 THEN 1 ELSE MAX(月份) + 1 END AS nextMonth, CASE WHEN MAX(月份) = 12 THEN 年份 + 1 ELSE 年份 END AS nextYear FROM FUND_PERIOD WHERE 是否已结账 = 1 AND 年份 >= #{startYear} AND 年份 <= #{endYear} GROUP BY 年份 ) latest ON p.年份 = latest.nextYear AND p.月份 = latest.nextMonth WHERE b.账户编号 IN
#{id}
ORDER BY latest.年份 ASC, b.账户编号 ASC

SELECT 账户编号 AS accountId, DATE_FORMAT(交易日期, '%H:%i:%s') AS transactionTime, 交易金额 AS amount, 交易类型 AS transactionType, COALESCE(备注, '') AS remark FROM FUND_TRANSACTION WHERE 账户编号 IN
#{id}
AND DATE_FORMAT(交易日期, '%Y-%m-%d') = #{date} ORDER BY 交易日期 ASC
